END $$;

-- ── 4. Build transit graph (directed edges) ────────────────────────────────
INSERT INTO transit_graph (from_stop_id, to_stop_id, route_id, cost_minutes, fare_kes)
SELECT
  rs1.stop_id, rs2.stop_id, rs1.route_id,
  -- Haversine travel-time estimate (no PostGIS needed): distance_m / 1000 / 30 km/h * 60 min
  GREATEST(1, ROUND((
    6371000 * 2 * ASIN(SQRT(
      POWER(SIN(RADIANS((s2.lat - s1.lat) / 2)), 2) +
      COS(RADIANS(s1.lat)) * COS(RADIANS(s2.lat)) * POWER(SIN(RADIANS((s2.lon - s1.lon) / 2)), 2)
    )) / 1000.0 / 30.0 * 60.0
  )::numeric, 1)::float),
  60  -- placeholder fare; updated by conductor per trip
FROM route_stops rs1
JOIN route_stops rs2 ON rs2.route_id = rs1.route_id AND rs2.stop_sequence = rs1.stop_sequence + 1
JOIN transit_stops s1 ON s1.id = rs1.stop_id
JOIN transit_stops s2 ON s2.id = rs2.stop_id
ON CONFLICT DO NOTHING;

-- Reverse edges
INSERT INTO transit_graph (from_stop_id, to_stop_id, route_id, cost_minutes, fare_kes)
SELECT to_stop_id, from_stop_id, route_id, cost_minutes, fare_kes
FROM transit_graph
ON CONFLICT DO NOTHING;

